    model="fast",
)
h4 = delegate(
    "index_html_writer",
    "Write file to output/boids-simulation/index.html with the EXACT content in CONTEXT. Return only OK.",
    index_html,
    model="fast",
)

results = yield wait(h1, h2, h3, h4)
print("Children finished:", results)
# End block 1. The runtime will resume us for verification.

