function normalize(x, y) {
  const m = Math.hypot(x, y) || 1e-6;
  return { x: x / m, y: y / m };
}
function limit(x, y, max) {
  const m = Math.hypot(x, y);
  if (m > max) {
    const s = max / (m || 1e-6);
    return { x: x * s, y: y * s };
  }
  return { x, y };
